/// <summary>
/// This is an extension class for PurchEditLines form, PurchParmLine datasource and ETGImportReportFields field.
/// </summary>
[ExtensionOf(formDataFieldStr(PurchEditLines, PurchParmLine, ETGImportReportFields))]
internal final class ETGPurchEditLines_PurchParmLine_ImportReportFields_Extension
{
}

Method.Source:
/// <summary>
/// When ETGImportReportFields field is modified then making assessmentValue, VATPercentage, ExciseDuty
/// fields as visible and mandatory.
/// </summary>
public void modified()
{
    FormDataObject formDataObject = any2Object(this) as FormDataObject;
    FormDataSource formDataSource = formDataObject.datasource();

    next modified();

    PurchParmLine purchParmLine = formDataSource.cursor();
    if(purchParmLine.ETGImportReportFields == NoYes::Yes)
    {
        formDataSource.object(fieldNum(PurchParmLine, ETGAssessmentValue)).visible(true);
        formDataSource.object(fieldNum(PurchParmLine, ETGVATPercentage)).visible(true);
        formDataSource.object(fieldNum(PurchParmLine, ETGExciseDuty)).visible(true);
        formDataSource.object(fieldNum(PurchParmLine, ETGAssessmentValue)).mandatory(true);
    }
    else
    {
        formDataSource.object(fieldNum(PurchParmLine, ETGAssessmentValue)).visible(false);
        formDataSource.object(fieldNum(PurchParmLine, ETGVATPercentage)).visible(false);
        formDataSource.object(fieldNum(PurchParmLine, ETGExciseDuty)).visible(false);

        formDataSource.object(fieldNum(PurchParmLine, ETGAssessmentValue)).mandatory(false);
        formDataSource.object(fieldNum(PurchParmLine, ETGVATPercentage)).mandatory(false);
        formDataSource.object(fieldNum(PurchParmLine, ETGExciseDuty)).mandatory(false);

    }
}
